// 你写的代码：
console.log(x);  // undefined
var x = 5;
console.log(x);  // 5

// 引擎实际执行：
var x;              // ← 声明被提升到顶部
console.log(x);     // undefined (有声明但没赋值)
x = 5;              // ← 赋值留在原位
console.log(x);     // 5

// 可以在声明前调用！
greet();  // "Hello!" ✅

function greet() {
  return "Hello!";
}
// 引擎把整个函数定义提升到顶部

// 函数表达式（赋值给变量）
sayHi();  // ❌ TypeError: sayHi is not a function

var sayHi = function() {
  return "Hi!";
};
// 等价于：var sayHi; → sayHi = function...
// 提升的只是 var sayHi（undefined），不是函数本身

// TDZ（Temporal Dead Zone，暂时性死区）
// 从作用域开始到声明语句之间，变量存在但"禁止访问"

console.log(y);  // ❌ ReferenceError!
let y = 5;       // ← 声明点，TDZ 结束
console.log(y);  // 5 ✅ 安全访问

// TDZ 从块的开头开始，不是从声明行开始
{
  // TDZ 开始 ← 这里 x 已经存在但不能访问
  console.log("before");
  // console.log(x);  // ❌ ReferenceError
  let x = 42;       // TDZ 结束
  console.log(x);    // 42 ✅
}

// const 同样有 TDZ
{
  // console.log(PI);  // ❌ ReferenceError
  const PI = 3.14;    // TDZ 结束
  console.log(PI);    // 3.14 ✅
}

// ── var ──
console.log(a);  // undefined (提升+初始化为undefined)
var a = 1;

// ── let ──
console.log(b);  // ❌ ReferenceError (提升但TDZ)
let b = 2;

// ── const ──
console.log(c);  // ❌ ReferenceError (提升但TDZ)
const c = 3;

// ── function ──
console.log(d);  // ƒ d() (整体提升)
function d() {}

var name = "Alice";
function greet() {
  // var name 被提升到函数顶部（undefined）
  if (!name) {
    var name = "Bob";  // 本意是检查全局name
  }
  console.log(name);  // "Bob" ← 不是 "Alice"!
}
// 原因：var name 提升到 greet 顶部
// if 检查的是局部 undefined，不是全局 "Alice"

for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// 输出: 3, 3, 3
// var i 提升到函数/全局作用域
// 3个回调共享同一个i

// 修复1：let 不会覆盖外层
let name = "Alice";
function greet() {
  // let name 有TDZ，不会提前为undefined
  if (!name) {  // 正确引用全局 "Alice"
    let name = "Bob";  // 块级作用域
  }
}

// 修复2：let 循环
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}
// 输出: 0, 1, 2 ✅

// ✅ 安全写法：先声明再使用
const API = "url";    // 不会变的值 → const
let count = 0;       // 计数器 → let
function init() {}   // 函数声明 OK

// ❌ 危险写法
var x;               // 永远不用var！
console.log(y);     // 使用前必须声明！
let y = 1;
